// ---- Step 10: diff watched fields against last snapshot -> one item per change ----
// NOTE: $getWorkflowStaticData persists only when the workflow is ACTIVE (production runs),
// not in manual test runs. First sighting of a record only seeds the snapshot (no log spam).
const sd = $getWorkflowStaticData('global');
sd.snapshots = sd.snapshots || {};
const WATCH = ['Status', 'Priority', 'Category', 'Assigned Team', 'Internal Notes'];
const VALID_STATUS = ['Open', 'In Progress', 'Waiting for Customer', 'Resolved', 'Closed'];
const out = [];
for (const item of $input.all()) {
  const f = item.json.fields || item.json;
  const rid = item.json.id;
  if (!rid) continue;
  const prev = sd.snapshots[rid];
  if (prev) {
    for (const field of WATCH) {
      const oldV = prev[field] !== undefined && prev[field] !== null ? prev[field] : '';
      const newV = f[field] !== undefined && f[field] !== null ? f[field] : '';
      if (JSON.stringify(oldV) !== JSON.stringify(newV)) {
        const illegalStatus = field === 'Status' && newV && !VALID_STATUS.includes(String(newV));
        out.push({
          json: {
            recordId: rid,
            ticketId: f['Ticket ID'] || '',
            field,
            oldValue: String(oldV),
            newValue: String(newV),
            changedBy: 'agent (via Airtable)',
            illegalStatus,
            statusNowResolved: field === 'Status' && String(newV) === 'Resolved',
            statusNowWaiting: field === 'Status' && String(newV) === 'Waiting for Customer',
            senderEmail: f['Sender Email'] || '',
            customerName: f['Customer Name'] || 'there',
            issueSummary: f['Issue Summary'] || '',
          },
        });
      }
    }
  }
  const snap = {};
  for (const field of WATCH) snap[field] = f[field] !== undefined && f[field] !== null ? f[field] : '';
  sd.snapshots[rid] = snap;
}
return out; // empty = nothing meaningful changed

